import React, { useEffect, useState } from "react";
import API from "../../api/api";

const Earnings = () => {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading]     = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await API.get("/proposals/my");
        setProposals(res.data || []);
      } catch {}
      setLoading(false);
    };
    fetch();
  }, []);

  const accepted   = proposals.filter(p => p.status === "accepted");
  const pending    = proposals.filter(p => !p.status || p.status === "pending");
  const rejected   = proposals.filter(p => p.status === "rejected");
  const totalEarned  = accepted.reduce((s, p) => s + parseFloat(p.bid || 0), 0);
  const totalPending = pending.reduce((s, p) => s + parseFloat(p.bid || 0), 0);

  const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

  const statusStyle = (s) => {
    if (s === "accepted") return "bg-green-100 text-green-700";
    if (s === "rejected") return "bg-red-100 text-red-600";
    return "bg-yellow-100 text-yellow-700";
  };

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">
        <h1 className="text-2xl font-bold text-gray-800 mb-2">Earnings Dashboard</h1>
        <p className="text-gray-500 mb-6">Track your bids and income</p>

        {/* STAT CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          {[
            { label: "Total Earned", value: `₹${totalEarned.toLocaleString()}`, color: "border-green-500", text: "text-green-600" },
            { label: "Pending Value", value: `₹${totalPending.toLocaleString()}`, color: "border-yellow-500", text: "text-yellow-600" },
            { label: "Accepted Jobs", value: accepted.length, color: "border-blue-500", text: "text-blue-600" },
            { label: "Total Proposals", value: proposals.length, color: "border-teal-500", text: "text-teal-600" },
          ].map((s, i) => (
            <div key={i} className={`bg-white rounded-xl p-5 shadow-sm border-l-4 ${s.color}`}>
              <p className="text-sm text-gray-500">{s.label}</p>
              <p className={`text-2xl font-bold mt-1 ${s.text}`}>{s.value}</p>
            </div>
          ))}
        </div>

        {/* STATUS BREAKDOWN */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          {[
            { label: "✅ Accepted", count: accepted.length, bg: "bg-green-50", text: "text-green-700" },
            { label: "⏳ Pending",  count: pending.length,  bg: "bg-yellow-50", text: "text-yellow-700" },
            { label: "❌ Rejected", count: rejected.length, bg: "bg-red-50",    text: "text-red-600" },
          ].map((b, i) => (
            <div key={i} className={`${b.bg} rounded-xl p-4 text-center`}>
              <p className={`text-3xl font-bold ${b.text}`}>{b.count}</p>
              <p className={`text-sm mt-1 ${b.text}`}>{b.label}</p>
            </div>
          ))}
        </div>

        {/* PROPOSALS TABLE */}
        <div className="bg-white rounded-xl shadow overflow-hidden">
          <div className="p-4 border-b">
            <h2 className="font-bold text-gray-700">All Proposals & Earnings</h2>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Project</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Your Bid</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Project Budget</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Date</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {proposals.length === 0 ? (
                <tr><td colSpan={5} className="text-center py-8 text-gray-400">No proposals yet.</td></tr>
              ) : proposals.map(p => (
                <tr key={p.id} className="hover:bg-gray-50">
                  <td className="px-5 py-4 font-medium text-gray-800">{p.project_title}</td>
                  <td className="px-5 py-4 font-bold text-teal-600">₹{p.bid}</td>
                  <td className="px-5 py-4 text-gray-500">₹{p.project_budget || "—"}</td>
                  <td className="px-5 py-4 text-gray-400">{formatDate(p.created_at)}</td>
                  <td className="px-5 py-4">
                    <span className={`px-2 py-1 rounded-full text-xs font-semibold capitalize ${statusStyle(p.status)}`}>
                      {p.status || "pending"}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Earnings;
